export type Cell = [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const neighborsOf = ([x, y]: Cell): Cell[] => {
  const neighbors: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      neighbors.push([x + dx, y + dy]);
    }
  }
  return neighbors;
};

export function nextGeneration(livingCells: Cell[]): Cell[] {
  const liveKeys = new Set(livingCells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const cell of livingCells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = cellKey(neighbor);
      const entry = neighborCounts.get(k);
      if (entry) entry.count++;
      else neighborCounts.set(k, { cell: neighbor, count: 1 });
    }
  }

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    const survives = count === 3 || (count === 2 && liveKeys.has(k));
    if (survives) result.push(cell);
  }
  return result;
}
